export const providers = [
  // ---------- LEADERSHIP ----------
  { slug: "kristine-a-schlichting-ph-d", name: "Kristine Schlichting, PhD", credentials: "PhD", role: "Director & Founder", category: "leadership", photo: "kristine-a-schlichting-phd", prescribes: false,
    education: "Doctorate and master's in psychology, University of Connecticut; additional master's in counseling, University of Wisconsin–Madison",
    focus: ["Anxiety disorders", "Mood disorders", "Divorce & blended families", "Women's issues", "Sex & intimacy concerns", "Gottman Method couples", "Testing & diagnosis"],
    quote: null,
    bio: "Dr. Kristine Schlichting, PHD, is the Director of Hopewell Health Solutions and a Licensed Psychologist fusing together the principles of psychology, transformation, motivation, coaching, and wellness. She earned her doctorate and masters' in psychology at the University of Connecticut and received an additional master's in counseling at the University of Wisconsin- Madison.\n\nOver the past ten years, Dr. Schlichting has “broken the box” of traditional talk therapy to develop a new model for change which is based on recent developments in neuroscience. Therapy at HHS is active, dynamic, and collaborative; this therapy requires discipline, practice, and teaming with the client. Guiding her staff in this treatment ensures that every HHS therapist's work is rooted in this practice.\n\nDr. Schlichting has conducted research in the areas of anxiety, group dynamics, and video self-modeling. Her innovative research has been published in various articles and books. Her most recent book was published in 2018, “The Parenting Project.” Dr. Schlichting is always looking for new opportunities to put mental health on the forefront – including co-locating her therapists in doctor's offices, providing telehealth, providing therapy in natural settings (home, office, or school), and using technology to help patients.\n\nDr. K is a fierce advocate committed to helping all children and adults reach their fullest potential. In her free time, she enjoys having adrenaline filled adventures with her children and fur baby." },
  { slug: "teesha-huertas-lcsw", name: "Teesha Huertas, LCSW", credentials: "LCSW", role: "Clinic Director & Licensed Clinical Social Worker", category: "leadership", photo: "teesha-huertas-lcsw", prescribes: false,
    education: "BA in Psychology and Master's in Social Work, University of Connecticut",
    focus: ["Substance use & co-occurring disorders", "Depression", "Anxiety", "PTSD & trauma (EMDR, CPT)", "Mood disorders"],
    quote: "“To take more than you give is to fail at life.” — Clayton Gengras",
    bio: "Teesha is a Licensed Clinical Social Worker who graduated from UConn with her BA in Psychology and Master's in Social Work. Teesha has been in the Behavioral Health field for a decade now and has worked in a variety of settings. Teesha's clinical experience has come from working as a case manager, inpatient and outpatient clinician, crisis worker, and clinical director in Substance Use Rehabilitation Programs. Teesha is an experienced leader who leads with compassion, ethics, and discipline. She believes in guiding and motivating the people she works with to develop the skills necessary for strategic decision making and the execution of goals and growth.\n\nTeesha has a self-proclaimed passion for working with adults with substance use and co-occurring disorders. Teesha specializes in substance use and mental health challenges including depression, anxiety, PTSD, and mood disorders. Teesha is both EMDR (Eye-Movement Desensitization and Reprocessing) and CPT (Cognitive Processing Therapy) trained to help those struggling with trauma. Additional therapeutic approaches Teesha utilizes include Cognitive Behavioral Therapy (CBT), Dialectical Behavioral Therapy (DBT), psychodynamic therapy, AcuDetox, and solution-focused techniques, to help clients develop coping skills, improve mental health, and work through life challenges.\n\nTeesha believes therapy is a team collaboration between the client and the clinician built on mutual respect, trust, and open communication. Effective treatment begins with recognizing that there is no one-size-fits-all approach to healing. Every individual brings a unique set of experiences, strengths, and challenges, and clinical care should reflect that complexity. Teesha's approach emphasizes meeting clients where they are, integrating evidence-based practices with individualized care that respects each person's story, culture, and goals.\n\nOutside of Teesha's professional life, she enjoys spending time with her family, adventures outdoors, and is an avid reader." },
  { slug: "colleen-callaway-mba", name: "Colleen Callaway, MBA", credentials: "MBA", role: "Office Manager", category: "leadership", photo: "colleen-callaway-mba", prescribes: false,
    education: "BA in Psychology (minor in Social Work), Marist College; MBA in Management, Long Island University",
    focus: [],
    quote: null,
    bio: "Colleen is the office manager for Hopewell Health Solutions. She manages the treatment schedule, checks on benefits and insurance, and helps with customer relations. Colleen is a graduate of Marist College with a degree in psychology and a minor in social work. She has a Master's in Business Administration with a concentration in Management from Long Island University. Colleen has many years of experience in the business field. When Colleen is not working, she enjoys running and spending time with her husband, kids and two dogs." },
  { slug: "tj-aitken-cpsrp", name: "TJ Aitken, CPSRP", credentials: "CPSRP", role: "Director of Business Development", category: "leadership", photo: "tj-aitken-cpsrp", prescribes: false,
    education: "Certified Peer Support and Recovery Professional (CPSRP) · Recovery Coach Professional",
    focus: ["Substance use & recovery", "Peer support & recovery coaching", "Young people & families", "Trauma-informed programming"],
    quote: null,
    bio: "A person in long-term recovery, TJ brings both lived experience and professional expertise to his work in the substance use and recovery field. As a Certified Peer Support and Recovery Professional (CPSRP) and Recovery Coach Professional, he has spent the past 10 years working in the substance use field, supporting individuals and families through compassionate, recovery-oriented care. His work is grounded in the belief that recovery is possible, sustainable, and strengthened through connection and community.\n\nOver the last five years, he has served in leadership and management roles, where he designed, implemented, and oversaw programming specifically focused on young people and their families. His leadership has centered on building inclusive, trauma-informed environments, developing peer-driven services, mentoring staff, and creating programs that meet individuals where they are while encouraging long-term growth and stability. He is recognized as a leader within the young people's recovery community, advocating for youth-centered approaches that honor autonomy, resilience, and hope.\n\nKnown for his collaborative and relational leadership style, he emphasizes empowerment, accountability, and sustainability in both individuals and organizations. He values strong teams, authentic relationships, and systems that support recovery beyond crisis, helping communities move toward lasting wellness.\n\nOutside of his professional life, he is a devoted husband and father who prioritizes family and fellowship. When he is not working or spending time with loved ones, he finds balance hiking in the woods with his Doberman, watching football, playing golf, or unwinding with a guitar—activities that support a grounded and intentional life in recovery." },

  // ---------- MEDICAL STAFF ----------
  { slug: "katrin-moskowitz-dnp-pmhnp-bc-fnp", name: "Katrin Moskowitz, DNP, PMHNP-BC, FNP", credentials: "DNP, PMHNP-BC, FNP", role: "Board-Certified Psychiatric & Family Nurse Practitioner", category: "medical", photo: "katrin-moskowitz-dnp-pmhnp-bc-fnp", prescribes: true,
    education: "BSN, Drexel University (2011); MSN Family Practice (2013), DNP (2015), and post-master's Psychiatric Mental Health (2019), all from Frontier Nursing University",
    focus: ["Psychiatric evaluation & diagnosis", "Medication management — children, teens & adults", "Anxiety, mood & personality disorders", "ADHD, OCD & addiction", "Insomnia & sleep", "LGBTQ+ affirming care"],
    quote: null,
    bio: "Dr. Katrin “Kat” Moskowitz is a distinguished dual board-certified practitioner specializing in psychiatric mental health and family nursing. Renowned for her dedication to compassionate, evidence-based, and holistic whole health care, Dr. Moskowitz has worked in both general medicine and mental health for over 15 years and made significant strides in diverse medical environments.\n\nKatrin commenced her journey in healthcare with a Bachelor of Science in Nursing from Drexel University in 2011. She then advanced her expertise by earning a Master's in Nursing, specializing in Family Practice, in 2013, followed by a Doctorate in Nursing Practice in 2015, and a post master's in Psychiatric Mental Health in 2019, all from Frontier Nursing University.\n\nThroughout her expansive career, she has provided medical care across the lifespan, from newborns to adults, in settings including ER, Urgent Care, Family Practice, and Substance Use and Mental Health Treatment. Her specialized training encompasses addiction disorders, mental health disorders, and holistic treatments for clients to obtain optimal health, highlighting her commitment to diverse and inclusive healthcare practices.\n\nKatrin is committed to fostering collaborative relationships with her clients in a safe and supportive environment. She values honest dialogue, working towards optimal mental well-being, acknowledging the complexity and sensitivity these conversations can entail. She provides a balanced approach to care that incorporates lifestyle modifications, therapeutic strategies, and medication management.\n\nResiding in Torrington, Connecticut, Katrin enjoys a fulfilling life with her husband, two adult children, and two dogs. When she is not participating in military drills, she relishes hiking in the White Mountains, traveling to Disney World, or embarking on cruises to embrace life's adventures." },
  { slug: "tracy-sibley-pmhnp-bc-aprn", name: "Tracy Sibley, PMHNP-BC, APRN", credentials: "PMHNP-BC, APRN", role: "Board-Certified Psychiatric Mental Health Nurse Practitioner", category: "medical", photo: "tracy-sibley-pmhnp-bc-aprn", prescribes: true,
    education: "BSN, New England Institute of Technology; MSN, Walden University",
    focus: ["Children, teens & adults", "Acute psychiatric care", "Substance-abuse rehabilitation", "Mental health & addiction", "Medication management"],
    quote: null,
    bio: "Tracy Sibley, PMHNP-BC APRN, is a board-certified psychiatric mental health nurse practitioner with Hopewell Health Solutions, located in Glastonbury and West Hartford, Connecticut.\n\nTracy obtained her bachelor's degree in nursing from the New England Institute of Technology and her master's degree in nursing from Walden University. Tracy has served as a psychiatric nurse for the past eight years, working with children, teens, and adults in diverse environments such as acute psychiatric care, residential facilities, and substance abuse rehabilitation.\n\nAlongside her practical experience, Tracy is a distinguished recipient of the 2021 Nightingale Award and has demonstrated her exceptional ability to engage with individuals, comprehend their needs, and exhibit compassion to support them effectively. She is authentic, affable, energetic, honest, and genuinely committed to helping others achieve wellness and success.\n\nTracy strongly believes in mutual trust and respect and works with all of her patients to achieve full recovery, improved quality of life, and improved relationships and happiness. Tracy has observed the stigma associated with mental health and addiction and seeks to drive change by committing herself to assist others in maximizing their full potential. Tracy believes, “You are not a failure for struggling with your mental health. You are a champion for persevering in the face of adversity.”\n\nOutside of the office, Tracy enjoys spending time with family and friends and the company of her four dogs; she has a passion for the outdoors and enjoys watching her children participate in sports. She serves as a board member of her town's football club and strives to volunteer at her children's school events as frequently as possible. Tracy is a dedicated follower of UCONN Huskies basketball, enjoying both the men's and women's teams." },
  { slug: "alizah-smith-pmhnp-bc", name: "Alizah Smith, PMHNP-BC", credentials: "PMHNP-BC", role: "Board-Certified Psychiatric Nurse Practitioner", category: "medical", photo: "alizah-smith-pmhnp-bc", prescribes: true,
    education: "BSN, University of Connecticut (2008); MSN with specialization in psychiatry, Ohio University (2023)",
    focus: ["Acute & chronic psychiatric conditions", "Addiction disorders", "Children, teens & adults", "Psychiatric medication management"],
    quote: null,
    bio: "Alizah Smith, PMHNP-BC, is a board-certified psychiatric mental health nurse practitioner (PMHNP-BC) at Hopewell Health Solutions in Glastonbury, Connecticut. She has a strong commitment to delivering compassionate, evidence-based mental health care.\n\nAlizah completed her Bachelor of Science in Nursing at the University of Connecticut in 2008 and went on to obtain her Master of Science in Nursing with a specialization in psychiatry from Ohio University in 2023.\n\nOver the last 17 years, she has worked with kids, teens, and adults in a variety of inpatient and outpatient settings. Alizah has additional specific training working with addiction disorders and treating the whole person during the recovery process. Alizah treats both acute and chronic psychiatric conditions and works with children, teens, and adults at Hopewell Health Solutions.\n\nAlizah's goal is to work collaboratively with her clients in an environment that is safe and supportive. She promotes honest discussions that work towards her clients achieving their optimum state of mental well-being. This holistic approach is based on the understanding that when one area is off balance for a client, it will affect other aspects as well. She enjoys working with clients and helping them to find that balance, which can include lifestyle changes, therapeutic strategies, and medications.\n\nAlizah talks with her patients through difficult and complicated medical decisions, such as making psychiatric medication adjustments. Alizah is deeply committed to promoting mental wellness, reducing stigma, and empowering individuals through collaborative, person-centered treatment. She believes that a strong therapeutic alliance, combined with a comprehensive, individualized approach to care, can make a profound difference in a patient's recovery and overall well-being.\n\nCurrently residing in Glastonbury, Connecticut, Alizah enjoys life with her husband, two children, and their dog, Willow. When she is not driving her children to all of their activities, she finds enjoyment in hiking, practicing yoga, traveling, reading, and spending time with friends. She is a lifelong learner, continually pursuing professional development to provide the most effective and up-to-date care for her patients." },
  { slug: "chris-patenaude-pa", name: "Christopher Patenaude, PA", credentials: "PA", role: "Board-Certified Physician Assistant", category: "medical", photo: "chris-patenaude-pa", prescribes: true,
    education: "Master's in Physician Assistant Studies, Bay Path University",
    focus: ["Evidence-based medication management", "ADHD", "Bipolar disorder", "Schizophrenia", "Treatment-resistant depression", "Children, adolescents & adults"],
    quote: null,
    bio: "Christopher Patenaude, PA, is a board-certified physician assistant with specialized training in outpatient psychiatry. He provides compassionate care to patients at Hopewell Health Solutions, with locations in Glastonbury and West Hartford, Connecticut.\n\nChristopher earned his master's degree in Physician Assistant Studies from Bay Path University and has since dedicated his career to supporting the mental health needs of children, adolescents, and adults.\n\nChristopher has extensive experience treating a broad spectrum of psychiatric conditions, including ADHD, bipolar disorder, schizophrenia, and treatment-resistant depression. He takes a thoughtful, individualized approach to care—grounded in evidence-based medication management—and emphasizes open communication and shared decision-making with every patient.\n\nKnown for his compassionate and patient-centered style, Christopher creates a welcoming, nonjudgmental space where individuals feel heard, respected, and empowered to ask questions. He works closely with each patient to develop personalized treatment strategies aimed at improving daily functioning and overall quality of life.\n\nChristopher believes that mental health care is most effective when built on mutual trust and clear communication. His goal is to help each patient feel informed and confident in their treatment plan, whether they're navigating a new diagnosis or exploring long-term management strategies.\n\nOutside the office, Christopher enjoys hiking, exploring the outdoors, and spending time with his wife and their two dogs. He values the importance of balance and self-care, principles he encourages in his clinical work and daily life." },
  { slug: "rosa-kleinberg-aprn-pmhnp-bc", name: "Rosa Kleinberg, APRN, PMHNP-BC", credentials: "MSN, APRN, PMHNP-BC", role: "Board-Certified Psychiatric Nurse Practitioner", category: "medical", photo: "rosa-kleinberg-aprn-pmhnp-bc", prescribes: true,
    education: "BSN, Western Connecticut State University; MSN, University of Saint Joseph",
    focus: ["Depression & anxiety", "ADD/ADHD", "Trauma & autism", "Substance use disorders", "Personality disorders & OCD", "Psychiatric evaluation & medication management"],
    quote: null,
    bio: "Rosa Maria Kleinberg, MSN APRN PMHNP-BC, is a board-certified psychiatric mental nurse practitioner at Hopewell Health Solutions, which is based in Glastonbury and West Hartford, Connecticut. Rosa received her bachelor's degree in nursing from Western Connecticut State University and graduated with high honors while earning a master's degree in nursing from the University of Saint Joseph. Rosa is an experienced nurse practitioner with over 15 years of experience as a nurse in a Level 1 Trauma Center ICU setting and a variety of psychiatric settings, which gives her a unique perspective on her clients' psychiatric and medical needs. Rosa treats both acute and chronic psychiatric conditions and works with children, teens, and adults at Hopewell Health Solutions.\n\nRosa's therapeutic approach is very holistic and comprehensive. She treats patients that have symptoms of depression, anxiety, ADD/ ADHD, trauma, Autism, substance use disorders, personality and OCD disorders. Rosa believes in creating an individualized plan of care that values client involvement, interprofessional collaboration, and evidence-based practice. Rosa's goal is to empower her clients and treat their illnesses through supportive education in a stigma-free environment. Rosa has the pleasure of working alongside many skilled and experienced clinicians and is happy to collaborate and coordinate care with them when appropriate to the client's needs. She believes strongly in using a blend of CBT and DBT and motivational skills during her sessions, to help clients alleviate presenting symptoms in addition to medication management. Rosa is a strong advocate for her clients and has a centered patient approach and talks with her patients through difficult medical decisions, such as making psychiatric medication adjustments.\n\nRosa is trilingual and fluent in English, Spanish, and Portuguese (Conversational). In her free time, Rosa loves spending time with her family, traveling, trying different foods, and practicing Zumba and yoga." },
  { slug: "katherine-salvador-pa-c", name: "Katherine Salvador, PA-C", credentials: "PA-C", role: "Board-Certified Physician Assistant", category: "medical", photo: "katherine-salvador-pa-c", prescribes: true,
    education: "Bachelor's and Master's degrees, Springfield College (clinical training in inpatient psychiatry)",
    focus: ["Mood disorders", "Anxiety", "Substance use disorders", "Acute & chronic psychiatric conditions", "Psychopharmacology & medication management"],
    quote: null,
    bio: "Katherine Salvador, PA-C, is a board-certified physician assistant at Hopewell Health Solutions, which has locations in Glastonbury and West Hartford, Connecticut.\n\nKatherine received her Bachelor's and Master's degrees from Springfield College, where she completed her clinical training in psychiatry in the inpatient hospital setting. After graduating, Katherine focused her career on community-based mental health and addiction treatment. Her knowledge of psychopharmacology stems from over nine years' experience treating a wide scope of mental health conditions including mood, anxiety, and substance use disorders throughout the clinic, hospital, and addiction treatment environments.\n\nKatherine is, herself, an ever-learning student of mindfulness and believes strongly in the power of being “still.” She believes that the use of medication, in combination with cognitive therapies like mindfulness, or other types of psychotherapy, can be life-changing.\n\nKatherine works with clients who are experiencing both acute and chronic psychiatric conditions. She knows that making decisions about medication can be difficult, and her goal is to create an open and safe space for clients to express their hopes, concerns, and fears as they relate to medication treatment.\n\nKatherine lives in East Granby with her husband, daughter, and dog, Pepper. She is navigating life as a new mom and when she is not googling “how to get baby to sleep through the night” she enjoys yoga, decorating her home, Dave Matthews Band concerts, and spending time with family and friends." },

  // ---------- PSYCHOLOGY ----------
  { slug: "eric-schwartz-psy-d-abpp", name: "Eric Schwartz, Psy.D., ABPP", credentials: "Psy.D., ABPP", role: "Licensed Psychologist · Board Certified in Clinical Child & Adolescent Psychology", category: "psychology", photo: "eric-schwarz-psyd-abpp", prescribes: false,
    education: "Psy.D., University of Denver, Graduate School of Professional Psychology; ABPP Board Certified in Clinical Child & Adolescent Psychology",
    focus: ["Children & adolescents", "Trauma & attachment disruptions", "Emotional & behavioral challenges", "Play therapy", "Parent-child work", "Family consultation"],
    quote: "“Children need the freedom and time to play. Play is not a luxury. Play is a necessity.” — Kay Redfield Jamison",
    bio: "Dr. Eric Schwartz, Psy.D., ABPP is a licensed psychologist and is Board Certified in Clinical Child and Adolescent Psychology. Dr. Schwartz has over 30 years of experience working with children, adolescents, and their families to promote growth, support healing, improve communication, and empower lasting and sustainable change through practical, collaborative problem-solving strategies.\n\nDr. Schwartz received his doctorate from the University of Denver, Graduate School of Professional Psychology. His career has included clinical and leadership roles in hospitals, community mental health center's, non-profit organizations, and private practice. Dr. Schwartz has also been published in peer-reviewed journals on topics related to children's behavioral health. Most recently, Dr. Schwartz was the Senior Vice President of Clinical Programs, Intensive Children's Services at The Village for Families and Children in Hartford. He also spent twenty-two years as Vice President of Clinical Services and Director of Psychology Internship Training at the Sarah Reed Children's Center in Erie, Pennsylvania. As Director of Training, he has supervised and mentored more than 60 professional psychologists who are now actively practicing in their careers all over the U.S.\n\nDr. Schwartz has specialized training in working with children who struggle with emotional and behavioral challenges, trauma, and the impact of early attachment disruptions. He believes deeply that when working with people who have survived traumatic experiences, the most important question to ask in gaining an empathic understanding of how trauma has impacted them, is not “what is wrong with the person”, but “What has happened to the person”. He has extensive experience in play therapy and individual therapy with kids and adolescents and parent-child work. His work with families is best described as consultative, believing that families function best when they see themselves as the experts, who at times need additional guidance, direction, and support in their journey to healing and improved functioning. His approach to therapy is one born of understanding that at any point in time children and families are doing the best they can and inherently seek out ways to lead more satisfying and healthier lives. He focuses on people's strengths and partners with the people he works with to find alternative paths to improved health and wellness.\n\nAt Hopewell Health Solutions, Dr. Schwartz's practice will primarily focus on children, adolescents, and their families. He also has some availability to see individual adults who may be struggling with life transition issues, parenting concerns, and those who are interested and motivated to gain a better understanding of themselves with the goal of leading a more satisfying life. Dr. Schwartz's other professional interests include clinical supervision and program development.\n\nIn his spare time, Dr. Schwartz and his wife enjoys spending time visiting their daughter and her husband in New Hampshire and traveling as much as possible. He enjoys collecting antique advertising, playing scrabble, and rooting for the NY Mets and New York Rangers." },
  { slug: "ashley-singh-psy-d", name: "Ashley Singh, PsyD", credentials: "PsyD", role: "Clinical Psychologist · Identity-Focused Counseling", category: "psychology", photo: "ashley-singh-psyd", prescribes: false,
    education: "B.A. in Psychology, University of Connecticut; M.A. in Psychology and Psy.D. in Clinical Psychology, William James College",
    focus: ["Kids, teens & adults", "LGBTQIA+ individuals", "Identity-focused counseling", "Anxiety, depression, ADHD & trauma", "CBT, DBT & motivational interviewing"],
    quote: null,
    bio: "Dr. Singh is a mental health practitioner with advanced training in identity-focused counseling. She earned her B.A. in psychology from the University of Connecticut. Dr. Singh went on to earn her Masters in psychology and Psy.D. in clinical psychology from William James College. She completed her internship with a focus on psychological assessment.\n\nFollowing graduation, Dr. Singh went on to complete two years of postdoctoral training in identity-focused counseling at Connecticut College Student Counseling Services and continues working at the college as an Identity-Focused Counselor.\n\nAt Hopewell Health Solutions, Dr. Singh provides individual psychotherapy via telehealth. Dr. Singh has extensive training and experience working with individuals who struggle with anxiety, depression, ADHD, trauma, and identity-related issues. Dr. Singh practices through an eclectic lens and adapts her approach based on an individual's needs. She is trained in CBT, DBT, Motivational Interviewing, and trauma-informed care.\n\nDr. Singh lives in Mansfield with her husband and their dog. She enjoys hiking, spending time with family and friends, and traveling." },
  { slug: "chris-barclay-ph-d-bcba-ncsp", name: "Chris Barclay, Ph.D, BCBA, NCSP", credentials: "Ph.D, BCBA, NCSP", role: "Licensed Clinical Psychologist", category: "psychology", photo: "chris-barclay-phd-bcba-ncsp", prescribes: false,
    education: "B.A. in Psychology, Georgia State University; Doctorate in School Psychology, University of South Florida",
    focus: ["ADHD & Autism", "Trauma", "Depression & anxiety", "Disruptive behaviors", "Tween & teen caregivers", "Parenting & family sessions"],
    quote: "“Be curious, not judgmental.” ~ Unknown",
    bio: "Chris is a Licensed Psychologist and Behavior Analyst with over 15 years of school-based and outpatient experience working with children and adolescents in multiple settings. He holds a Bachelor's in Psychology from Georgia State University and a Doctorate in School Psychology from the University of South Florida.\n\nChris specializes in collaborative behavioral problem-solving with tween and teen caregivers, in both group and individual settings, to address difficulties related to ADHD, Autism, trauma, depression, anxiety, and disruptive behaviors.\n\nHis therapeutic approach blends aspects of Trauma-Informed Positive Behavior Supports (PBS), Psychoeducation, Motivational Interviewing, and Acceptance and Commitment Therapy (ACT). He believes families thrive best when parents embrace their role as an “emotion coach” rather than a referee, super-fan, or spectator. Chris has experience in general, special, therapeutic, and faith-based education settings as well as pediatric and recreational contexts. He is a leader in a clinical day school and has taught graduate-level psychology courses at Purdue Global and UCONN.\n\nOutside of work, Chris is a husband and father of two growing-and-always-going boys. Together, they enjoy hiking and canoeing on their local lake, playing soccer, and weekly movie nights and pancake breakfasts." },
  { slug: "laura-miller-ph-d", name: "Laura Miller, PhD", credentials: "PhD · Licensed Psychologist", role: "Neuropsychology Leader & Neuropsychological Testing", category: "psychology", photo: "laura-miller-phd", prescribes: false,
    education: "B.A. in Psychology, Vanderbilt University; M.A. in Psychology and Ph.D. in School Psychology, Syracuse University; APA-accredited internship in pediatric neuropsychology (Virginia Beach City Public Schools); postdoctoral training in pediatric neuropsychology (Mass General for Children at North Shore Medical Center & Child and Family Psychological Services)",
    focus: ["Comprehensive neuropsychological evaluations (children, adolescents & young adults)", "Psychoeducational evaluations, including IEEs", "Autism spectrum disorders", "ADHD", "Anxiety", "Learning disabilities"],
    quote: "“Tell me and I forget. Teach me and I remember. Involve me and I learn.” – Benjamin Franklin",
    bio: "Dr. Miller is a Licensed Psychologist with Advanced Training in Pediatric Neuropsychology. She earned her B.A. in psychology from Vanderbilt University. Dr. Miller went on to earn her masters in psychology and Ph.D. in school psychology from Syracuse University. She completed an APA accredited internship in Pediatric Neuropsychology from the Virginia Beach City Public Schools. Following graduation, Dr. Miller went on to complete two years of Postdoctoral training in pediatric neuropsychology with Mass General for Children at North Shore Medical Center and Child and Family Psychological Services. She practiced as a Pediatric Neuropsychologist in Massachusetts for four years before joining Hopewell Health Solutions. She currently works as an Assistant Professor of Psychiatry at UConn School of Medicine.\n\nAt Hopewell Health Solutions, Dr. Miller conducts comprehensive neuropsychological evaluations to answer questions addressing concerns such as autism spectrum disorders, ADHD, anxiety, and learning disabilities. Dr. Miller strives to help clients and their families better understand areas of strength and areas for improvement. She hopes that clients come away from evaluations learning more about themselves and how to apply that information to gain support and see improvements at home, at school, and in the community.\n\nDr. Miller lives in Glastonbury with her husband, two young daughters, and goofy dog. She loves going on adventures with her family, exercising, and baking." },
  { slug: "bido-aguessy-psy-d-lpc-a", name: "Bido Aguessy, Psy.D., LPC-A", credentials: "Psy.D., LPC-A", role: "Clinical Psychologist & Spiritual Care Specialist", category: "psychology", photo: "bido-aguessey-psyd-lpc-a", prescribes: false,
    education: "Doctorate in Psychology, Graduate Theological Foundation (Mishawka, IN); theological training at New Brunswick Theological Seminary and JFK Medical Center, NJ",
    focus: ["Trauma & PTSD", "Depression & anxiety", "Grief & loss", "Anger & mood disorders", "End-of-life, palliative care & geriatric depression", "7-week grief group therapy"],
    quote: "“When we tell our story, we become human.” — Parker Palmer",
    bio: "Dr. Bido Aguessy, Psy. D. is a clinical psychologist, a licensed professional counselor associate, and a spiritual care specialist. With a lifelong love of learning, he has many degrees and accomplishments. He graduated with a doctorate in psychology from the Graduate Theological Foundation in Mishawka, IN. Dr. Aguessy was passionate about learning about the intersection of spirituality with psychology and continued his theological training at New Brunswick Theological Seminary and JFK Medical center in NJ.\n\nHis early clinical work included supporting patients in their early stage of disability at the Kessler Institute of Rehabilitation in NJ. In addition, most of his research and clinical work is concentrated on End of Life, palliative care, grief and loss. Dr. Aguessy has worked as a grief counselor for the Connecticut Hospice. Dr. Aguessy has also worked as a counselor at Hartford Hospital, University of Connecticut Health, Trinity Health of New England, and Athena Health.\n\nDr. Bido Aguessy works with adolescents and adults that are experiencing trauma, PTSD (post-traumatic stress disorder), depression, anxiety, grief, mood disorders, and anger. He also works with the adults in the areas of geriatric depression and end of life. Dr. Aguessy's holistic philosophy includes working with the whole family and the individual to necessitate change and growth. As theologian, he integrates spirituality in his clinical approach. Dr. Aguessy is well-versed in psychological methods of Depth Psychology, Jungian psychology, and logo therapy. He also works within a family systems perspective and is culturally sensitive. He is the author of a few therapeutic methods, like the Seven-week grief group therapy. Dr. Aguessy is also a published author of the book “Let's Talk about the End of Life Psychotherapy.” Dr. Aguessy is a fluent speaker of English, French, Ewe, Mina, and Fon languages." },

  // ---------- CLINICAL STAFF ----------
  { slug: "kaitlyn-czapiga-lmsw", name: "Kaitlyn Czapiga, LMSW", credentials: "LMSW", role: "Lead Clinician", category: "clinical", photo: null, prescribes: false,
    education: "Licensed Master Social Worker (LMSW)",
    focus: ["Women's Wellness IOP", "Trauma-informed group therapy", "DBT & CBT", "Depression & anxiety", "PTSD", "Emotional dysregulation & burnout"],
    quote: null,
    bio: "As lead clinician at Hopewell Health Solutions, I specialize in facilitating the Women's Wellness Intensive Outpatient Program (IOP), a trauma-informed, DBT- and CBT-based group therapy program designed to support adult women navigating complex mental health challenges such as depression, anxiety, PTSD, emotional dysregulation, and burnout. In this role, I lead psychoeducational and process-based group sessions." },
  { slug: "cassie-gittens-lpc-a", name: "Cassie Gittens, LPC-A", credentials: "LPC-A", role: "Licensed Professional Counselor – Associate", category: "clinical", photo: "cassie-gittens-lpc-a", prescribes: false,
    education: "Bachelor's and Master's (Clinical Mental Health Counseling), Grand Canyon University",
    focus: ["Complex trauma", "Individual, couples & family counseling", "LGBTQ+ affirming care", "Anxiety, depression, ADHD & life transitions", "Divorce & blended families"],
    quote: "“You have power over your mind – not outside events. Realize this, and you will find strength.” — Marcus Aurelius",
    bio: "I received my Bachelor's and Master's from Grand Canyon University. I earned my Master's degree in Clinical Mental Health Counseling. My approach is rooted in a person-centered and evidence-based framework. I utilize various therapeutic approaches, including Solution-Focused Therapy (SFT), Dialectical Behavioral Therapy (DBT), Emotional Freedom Technique (EFT), Crisis Intervention, Trauma Focused Therapy, Cognitive Behavioral Therapy (CBT), and Acceptance and Commitment Therapy (ACT).\n\nI have experience providing individual counseling services to adolescents ages 12–18 and adults, supporting clients as they navigate trauma, grief, and emotional challenges. I have also worked with families experiencing divorce and adjusting to blended family dynamics. I support family members in creating healthy ways to cope, building connections, and improving communication.\n\nI am passionate about helping people become their most authentic and empowered selves. My approach focuses on creating strong, trusting therapeutic relationships in a safe, compassionate setting as real transformation begins with connection. I believe that prioritizing mental health is essential to overall well-being. I am committed to walking alongside clients as they develop insight, resilience, and the tools needed to thrive in their daily lives.\n\nI enjoy being outside, watching sunsets and going on nature walks. In my spare time, I also like to travel." },
  { slug: "karmen-hayensworth-lmsw", name: "Karmen Hayensworth, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: null, prescribes: false,
    education: "Bachelor's in Experimental Psychology, University of South Carolina; Master's in Social Work, University of Southern California",
    focus: ["Youth, adults & families", "Substance use, PTSD, anxiety & depression", "Co-occurring disorders & IOP", "Self-esteem & life transitions", "Culturally competent, inclusive care"],
    quote: null,
    bio: "Karmen is a Licensed Master Social Worker with an extensive background working with substance use, trauma, anxiety, depression, and complex co-occurring disorders. Karmen has worked with kids, teens, and adults throughout her career. Karmen is an honest, loyal, and empathetic individual who will foster a safe and encouraging environment. She holds a Bachelor's degree in Experimental Psychology from the University of South Carolina and her Master's degree in Social Work from the University of Southern California.\n\nKarmen utilizes a client-centered approach, meeting clients where they are and tailoring treatment to their individual needs while honoring their unique experiences, strengths, and therapeutic goals. Drawing from evidence-based practices and trauma-informed care, Karmen helps clients explore the root causes of their challenges while building practical tools for resilience and emotional well-being. Karmen's work often integrates techniques from cognitive-behavioral therapy (CBT), mindfulness-based cognitive therapy (MBCT), motivational interviewing (MI), and acceptance & commitment therapy (ACT) to foster lasting change and empowerment.\n\nOutside of her clinical work, Karmen is dedicated to empowering individuals to recognize their true potential, grounding her practice in the belief that “we always have a choice; since we can only control what we think, feel, and do, let's be intentional about manifesting what we truly want out of life.”" },
  { slug: "kelly-fluckiger-lmsw", name: "Kelly Fluckiger, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: null, prescribes: false,
    education: "Bachelor's and Master's in Social Work, University of Connecticut",
    focus: ["Children, adolescents, adults & families", "LGBTQ+ communities", "Anxiety, depression, ADHD, bipolar, OCD & trauma", "Substance use & co-occurring concerns", "Stress, grief & self-esteem"],
    quote: "“Be kinder than necessary because everyone you meet is fighting some kind of battle.” — Unknown",
    bio: "Kelly is a Licensed Master Social Worker who works with adolescents, young adults, and adults from diverse backgrounds. She earned her Bachelor's and Master's in Social Work at the University of Connecticut. She completed her practicum in an integrated behavioral health setting, using a holistic approach to her care. Kelly combines evidence-based practices such as Cognitive Behavioral Therapy (CBT), Dialectical Behavioral Therapy (DBT), Motivational Interviewing (MI), and mindfulness practices with a strength-based approach to meet individuals where they are.\n\nOutside of work, Kelly enjoys being in nature, playing with her cat, and socializing with friends and family." },
  { slug: "erin-kruse-lmsw", name: "Erin Kruse, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "erin-kruse-lmsw", prescribes: false,
    education: "Bachelor's in Psychology, Worcester State University; Master's in Social Work (Individuals, Groups & Families), University of Connecticut",
    focus: ["Children, adolescents & young adults", "Life transitions & emotional regulation", "Self-esteem & anxiety", "Relationship challenges", "LGBTQ+ communities"],
    quote: "“Owning our story and loving ourselves through that process is the bravest thing that we'll ever do.” — Brené Brown",
    bio: "Erin Kruse, LMSW, earned her Bachelor's degree in Psychology from Worcester State University and continued her education by completing her Master's degree in Social Work with a concentration in Individuals, Groups, and Families from University of Connecticut. Erin works with children, adolescents, and young adults and is passionate about supporting individuals as they navigate life transitions, emotional challenges, relationship difficulties, and periods of personal growth and change.\n\nErin emphasizes the importance of creating a safe, supportive, and collaborative therapeutic environment where clients feel heard, understood, and empowered. She believes in meeting individuals where they are while helping them build on their existing strengths to foster resilience, confidence, and meaningful change. Erin has experience supporting clients experiencing anxiety, emotional and behavioral challenges, self-esteem concerns, social-emotional difficulties, family conflict, relationship concerns, and adjustment-related stressors.\n\nErin utilizes a psychodynamic, person-centered, and strength-based approach to therapy. She works collaboratively with clients to increase self-awareness, strengthen coping skills, improve emotional regulation, and develop healthier patterns within relationships and everyday life. Erin values the therapeutic relationship and strives to provide an individualized approach that honors each client's unique experiences, identities, and goals." },
  { slug: "amenah-thomas-lpc-a", name: "Amenah Thomas, LPC-A", credentials: "LPC-A", role: "Licensed Professional Counselor Associate", category: "clinical", photo: "amenah-thomas-lpc-a", prescribes: false,
    education: "Master's in Clinical Mental Health Counseling, Bay Path University",
    focus: ["Adolescents, adults & families", "LGBTQ+ affirming care", "Eating disorders", "Anxiety, depression, ADHD, mood & OCD", "Trauma & substance use", "Stress, grief & self-esteem"],
    quote: "“Nothing can dim the light that shines from within.” — Maya Angelou",
    bio: "Amenah Thomas is a Licensed Professional Counselor Associate with a Master's degree in Clinical Mental Health Counseling from Bay Path University in Massachusetts. She works with children, adolescents, and adults who are navigating a wide range of challenges, including trauma, life transitions, anxiety, ADHD, eating disorders, depression, and substance use concerns.\n\nAmenah believes in meeting individuals where they are, offering a therapeutic space grounded in empathy, respect, and cultural sensitivity. Her goal is to help clients feel safe, heard, and validated as they work through challenges, build insight, and reconnect with their inner strengths. She views therapy as a collaborative process rooted in trust, compassion, and personal growth. Amenah utilizes evidence-based approaches tailored to each individual's unique needs, including Cognitive Behavioral Therapy (CBT), Dialectical Behavior Therapy (DBT), Person-Centered Therapy, and Motivational Interviewing.\n\nOutside of her clinical work, Amenah enjoys traveling and immersing herself in new cultures, exploring new restaurants, and attending concerts and comedy shows. She values quality time with her partner, family, and her cat Fluff." },
  { slug: "viviana-alvarado-lpc-a", name: "Viviana Alvarado, LPC-A", credentials: "LPC-A", role: "Licensed Professional Counselor Associate", category: "clinical", photo: "viviana-alvarado-lpc-a", prescribes: false,
    education: "Bachelor's in Secondary Health Education, Pontifical Catholic University of Puerto Rico; Master's in Mental Health Counseling, Cambridge College",
    focus: ["Bilingual (Spanish) / bicultural care", "Children, adolescents, adults & families", "LGBTQ+ communities", "Anxiety, depression, ADHD, OCD & trauma", "Substance use & co-occurring concerns", "Women's concerns & family dynamics"],
    quote: null,
    bio: "Viviana believes that therapy is an exploration, not a “fix”. She earned her Bachelors degree in Secondary Health Education from the Pontifical Catholic University of Puerto Rico and a Master's in Mental Health Counseling from Cambridge College in Massachusetts. Her experience spans from working in various non-profit organizations and school systems where she has gained extensive experience working with both adults and children, helping them navigate through crisis, substance use, women's specific concerns, complex co-occurring disorders, and family dynamics utilizing a trauma-focused approach, Cognitive Behavioral Therapy (CBT), and Dialectical Behavior Therapy (DBT).\n\nViviana believes that the most profound work happens when you feel truly seen and supported. Her approach is centered on the belief that she is there to walk beside you, keeping you at the heart of your own roadmap. The therapeutic process she builds with individuals is an honest and structured one. She will move at your pace, navigating the twists and turns of your journey until the path forward feels clear.\n\nWhen not in the office, Viviana is likely embracing her nerdy side or out exploring. She loves discovering new restaurants and parks across the state but is just as happy staying in to hang out with her family and pets. Additionally, as a firm believer in the power of rest, she can often be found perfecting the art of a good nap." },
  { slug: "traci-schneider-maatc-lpc-a-atr-p", name: "Traci Schneider, MAATC, LPC-A, ATR-P", credentials: "MAATC, LPC-A, ATR-P", role: "Licensed Professional Counselor Associate & Art Therapist", category: "clinical", photo: "traci-schneider-maatc-lpc-a-atr-p", prescribes: false,
    education: "Master's in Art Therapy & Clinical Counseling, Albertus Magnus College; Bachelor's in Family Studies, University of Connecticut",
    focus: ["Children, adolescents, adults & families", "LGBTQ+ communities", "Anxiety, depression, ADHD, OCD & trauma", "Art as expression & nervous-system regulation", "Life transitions, relationship stress & caregiving"],
    quote: "“What Art offers is space – a certain breathing room for the spirit.” — John Updike",
    bio: "Traci is a licensed professional counselor associate and board-certified, provisionally registered art therapist who works with kids, teens, and adults experiencing burnout, emotional overwhelm, and the pressure to constantly hold everything together. She holds a Master's degree in Art Therapy and Clinical Counseling from Albertus Magnus College and a Bachelor's degree in Family Studies from the University of Connecticut.\n\nTraci has experience in higher levels of care and community mental health settings, working with both individuals and groups. She offers a warm, collaborative, and grounded approach, creating space for clients to slow down, reconnect with themselves, and heal in ways that don't rely solely on words.\n\nShe integrates art therapy with evidence-based counseling practices to support individuals navigating life transitions, anxiety, relationship stress, caregiving roles, and patterns of self-criticism. Her work is trauma-informed and strengths-based, using art as a tool for expression, insight, and nervous system regulation—no artistic experience required.\n\nOutside of her clinical work, Traci enjoys nature walks, experimenting with different art materials, spending time with her teenage children, and exploring the world with her partner." },
  { slug: "khentrell-graham-lmsw", name: "Khentrell Graham, LMSW", credentials: "LMSW", role: "Outpatient Clinician", category: "clinical", photo: "khentrell-graham-lmsw", prescribes: false,
    education: "Licensed Master Social Worker",
    focus: ["Middle & high schoolers and young adults", "Emotional regulation & coping skills", "Relationship challenges", "Self-awareness & mindfulness", "Trauma-informed CBT"],
    quote: null,
    bio: "With 15 years of experience dedicated to middle schoolers, high schoolers, and young adults, I understand the unique pressures and transitions that define these years. My practice is built on a simple, vital foundation: a safe, non-judgmental environment where you can truly be yourself.\n\nI believe that therapy is most effective when it is client centered. This means our work is a partnership where your voice and your goals come first. My approach is trauma-informed and grounded in Cognitive Behavioral Therapy (CBT), ensuring that we address the root of emotional distress while building practical, real-world solutions.\n\nWhether you are navigating a difficult season or looking to strengthen your emotional toolkit, I am here to provide a space where you feel heard, respected, and empowered. Let's work together to move toward a more grounded and self-aware version of you." },
  { slug: "sherrie-gaudet-lcsw", name: "Sherrie Gaudet, LCSW", credentials: "LCSW, LADC", role: "Licensed Clinical Social Worker & Licensed Drug & Alcohol Counselor", category: "clinical", photo: "sherrie-gaudet-lcsw", prescribes: false,
    education: "Graduate degree in Clinical Social Work, Southern Connecticut State University; BA in Psychology, Worcester State College",
    focus: ["Anxiety, depression & trauma", "Identity exploration", "Grief", "Addiction & co-occurring concerns", "LGBTQ+ communities", "Walk-and-talk / nature-based therapy"],
    quote: "“Never give up, for that is just the place and time that the tide will turn.” — Harriet Beecher Stowe",
    bio: "Sherrie is a holistic and integrative Licensed Clinical Social Worker (LCSW) and Licensed Drug and Alcohol Counselor (LADC) with more than 23 years of experience supporting individuals across the lifespan. She holds a graduate degree in Clinical Social Work from Southern Connecticut State University and an undergraduate degree in Psychology from Worcester State College. Over the past two decades, she has worked across community mental health, correctional settings, school-based programs, and outpatient care. Her extensive experience includes clinical supervision, organizational leadership, and statewide training initiatives focused on trauma, resilience, and provider wellbeing. Sherrie specializes in supporting adults navigating anxiety, depression, trauma, identity exploration, stress, grief, relationship patterns, addiction, and complex co-occurring concerns.\n\nSherrie is known for her grounded, collaborative, and empowering presence; qualities that shape every aspect of her work. She often shares a guiding belief that reflects her therapeutic philosophy: “Healing happens when people feel seen, supported, and safe enough to explore who they are and who they're becoming.” Her therapeutic approach integrates evidence-based practices including Cognitive Behavioral Therapy (CBT), Dialectical Behavior Therapy (DBT), mindfulness, and trauma-informed care with a strength-based, person-centered philosophy. She also incorporates experiential and nature-based strategies, such as walk and talk therapy, to support grounding, emotional regulation, and whole-person wellness.\n\nClients consistently describe Sherrie as warm, steady, and deeply present. She meets each person exactly where they are, offering a balance of compassion, insight, and practical tools. Her work is collaborative and empowering, helping clients understand their patterns, build resilience, and reconnect with their sense of purpose and self-worth.\n\nOutside of her clinical role, Sherrie enjoys spending time in nature, engaging in creative practices, and cultivating meaningful connections — all of which contribute to the grounded, balanced presence she brings to her work." },
  { slug: "kayla-orozco-lcsw", name: "Kayla Orozco, LCSW", credentials: "LCSW", role: "Licensed Clinical Social Worker", category: "clinical", photo: "kayla-orozco-lcsw", prescribes: false,
    education: "BA in Liberal Arts (minors in Psychology & Public Health Wellness), Southern Connecticut State University; MSW, Fordham University",
    focus: ["Children, adolescents & adults", "Anxiety & depressive disorders", "ADHD & behavioral disorders", "Trauma / PTSD", "Co-occurring / substance abuse", "Self-esteem & grief"],
    quote: "“Be the change you wish to see in the world.” — Mahatma Gandhi",
    bio: "Kayla is a Licensed Master Social Worker with extensive experience in both inpatient and outpatient settings over the past 7 years. She holds a Bachelor's degree in Liberal Arts with minors in Psychology and Public Health Wellness from Southern Connecticut State University, and a Master's degree in Social Work from Fordham University.\n\nKayla specializes in group and individual therapy, focusing on children, adolescents, and adults dealing with mental health challenges, behavioral issues, and substance abuse. Kayla has experience working with all age groups and has helped individuals and families tackle issues including: depression, anxiety, ADHD, trauma, substance abuse, and disruptive behaviors. She developed her skills working in residential, outpatient and, in-home settings with individuals from a variety of backgrounds. Kayla is adept at identifying core issues and collaboratively developing attainable goals with her clients.\n\nHer therapeutic approach includes Cognitive Behavioral Therapy (CBT), Dialectical Behavioral Therapy (DBT), Motivational Interviewing, Person-Centered Therapy, Play Therapy, Psychoeducation, Talk Therapy, Eco-therapy, and Role-Playing. Kayla is passionate about mindfulness and grounding techniques, believing in the power of quieting the mind to connect with one's inner self. Kayla develops tailored, innovative treatment approaches for her clients and guides them to success with accountability measures and real world application of the therapeutic tools.\n\nKayla's professional philosophy centers around meeting clients where they are, empowering them through education about their diagnoses, and fostering self-empowerment/improved self-esteem. She creates a safe, nonjudgmental environment to support clients in developing healthier thought patterns and behaviors.\n\nOutside of work, Kayla enjoys hiking, playing soccer, spending quality time with family, friends, and her dog Levi. As a former college athlete with 20 years of soccer experience, she brings dedication/positivity to her work within the community, advocating for and supporting individuals in need." },
  { slug: "natalia-de-lonardo-lpca", name: "Natalia De Lonardo, LPCA", credentials: "LPCA", role: "Licensed Professional Counselor Associate", category: "clinical", photo: "natalia-de-lonardo-lpca", prescribes: false,
    education: "BA in Psychology, University of Connecticut; Master's in Clinical Mental Health Counseling, Fairfield University",
    focus: ["Children, adolescents & families", "Trauma", "Anxiety, ADHD, bipolar & OCD", "Substance use / addictions", "Depression & life transitions", "LGBTQ+ communities"],
    quote: "“The most beautiful people we have known are those who have known defeat, suffering, struggle, and loss — and have found their way out of the depths.” — Elisabeth Kübler-Ross",
    bio: "Natalia earned her Bachelor of Arts in Psychology from the University of Connecticut and continued her training by completing a Master's degree in Clinical Mental Health Counseling at Fairfield University. She is deeply committed to helping clients feel seen, supported, and empowered, providing compassionate, client-centered care that encourages healing and personal growth.\n\nNatalia has experience working with children, adolescents, and parents in outpatient settings, supporting a wide range of emotional and behavioral challenges. She has worked extensively with youth who have experienced trauma, helping them build coping skills, feel safe, and strengthen resilience. She also works closely with parents to enhance parenting skills, improve communication, and foster healthier family relationships.\n\nShe has a strong interest in helping clients navigate anxiety, depression, self-esteem concerns, life transitions, and the lingering effects of past trauma. Natalia strives to create a warm, nonjudgmental environment where clients feel comfortable exploring their thoughts, emotions, and experiences.\n\nNatalia draws from evidence-based approaches including Cognitive Behavioral Therapy (CBT), Dialectical Behavior Therapy (DBT), and Person-Centered Therapy. She tailors her approach to meet each client's unique needs. Her work is guided by empathy, active listening, and a collaborative therapeutic relationship.\n\nOutside of her professional work, Natalia enjoys spending time with her family, drawing, and walking in nature." },
  { slug: "dori-bessette-crail-lmft", name: "Dori Bessette-Crail, LMFT", credentials: "LMFT", role: "Licensed Marriage & Family Therapist", category: "clinical", photo: "dori-bessette-crail-lmft", prescribes: false,
    education: "B.A. in Psychology, Eastern Connecticut State University; M.A. in Marriage & Family Therapy, University of Saint Joseph",
    focus: ["Individual, couples & family therapy", "Gottman principles", "Emotionally Focused Therapy", "Divorce mediation", "Clinical supervision"],
    quote: "“Connection is why we're here; it gives purpose and meaning to our lives.” — Brené Brown · “There is a crack in everything… that's how the light gets in.” — Leonard Cohen",
    bio: "Dori Bessette-Crail is a seasoned Licensed Marriage and Family Therapist with 24+ years of experience in the mental health field. Dori holds a Bachelor of Arts in Psychology from ECSU and a Master of Arts in Marriage and Family Therapy from the University of Saint Joseph. For 15 years Dori owned a private practice providing individual, couples and family therapy. She has extensive training in Gottman principles and Emotionally Focused Therapy and is a certified Divorce Mediator. Dori has served as Adjunct faculty for Graduate Studies in the Department of Psychology at Springfield College.\n\nAs a Behavioral Health Clinician at Hartford Healthcare's Backus and Windham Hospitals Center for Mental Health Dori provides evidence-based, client-centered care driven by best practices. Dori's approach to supervision is systems focused using the Self of the Therapist model and is passionate about advancing professional growth for emerging clinicians through supporting, mentoring, guiding and sharing theoretical knowledge and expertise in their journey toward skills enhancement and developing their own unique therapeutic style.\n\nOutside of professional life Dori enjoys the beach (and anything involving water) traveling, listening to live music, pickleball and spending time with family which includes her Olde English Bulldog, Stasiu." },
  { slug: "joanne-malinka-lcsw", name: "Joanne Malinka, LCSW", credentials: "LCSW", role: "Licensed Clinical Social Worker", category: "clinical", photo: "joanne-malinka-lcsw", prescribes: false,
    education: "Licensed Clinical Social Worker",
    focus: ["Trauma-informed care", "EMDR", "Internal Family Systems (IFS)", "Program development", "Clinical leadership"],
    quote: null,
    bio: "Joanne Malinka, LCSW, is a Licensed Clinical Social Worker with over 20 years of experience in behavioral health, with a strong background in program development, clinical leadership, and trauma-informed care. She has played a key role in developing and supporting behavioral health programs while working with individuals experiencing complex emotional and psychological challenges.\n\nShe is trained in EMDR and integrates Internal Family Systems (IFS) into her clinical work. Joanne's approach is collaborative, compassionate, and grounded in helping clients process trauma, build insight, and create lasting change.\n\nShe brings a unique blend of clinical expertise and systems-level perspective to her work." },
  { slug: "octavia-francis-person-lpc-a", name: "Octavia Francis-Person, LPC-A", credentials: "LPC-A", role: "Licensed Professional Counselor Associate", category: "clinical", photo: "octavia-francis-person-lpc-a", prescribes: false,
    education: "B.A. in Sociology (minor in Psychology), Central Connecticut State University; M.S. in Clinical Mental Health Counseling, Post University",
    focus: ["Children, adolescents & adults", "DBT & CBT", "Solution-Focused Therapy", "Person-Centered Therapy", "Goal-directed treatment & coping skills"],
    quote: "“You may not control all the events that happen to you, but you can decide not to be reduced by them.” — Maya Angelou",
    bio: "Octavia Francis earned her Bachelor of Arts in Sociology with a minor in Psychology from Central Connecticut State University and her Master of Science in Clinical Mental Health Counseling from Post University.\n\nShe has extensive experience working with children, adolescents, and adults in school and intensive outpatient (IOP) settings, supporting individuals facing a wide range of behavioral and mental health challenges. Octavia is passionate about empowering clients to regain control of their lives and move toward meaningful, fulfilled living.\n\nHer therapeutic style is grounded in collaboration, trust, and genuine connection. She strives to create a safe, respectful space where clients feel heard and supported. Recognizing the uniqueness of each individual, Octavia tailors' treatment to meet specific needs. She draws from evidence-based modalities including Dialectical Behavior Therapy (DBT), Cognitive Behavioral Therapy (CBT), Solution-Focused Therapy, and Person-Centered Therapy to create individualized treatment plans targeting both immediate concerns and long-term goals.\n\nCentral to her practice is fostering self-awareness and building a practical set of coping skills. Octavia emphasizes goal-directed treatment with accountability measures, allowing clients to track their progress throughout the process. Because real change happens beyond the therapy room, she focuses on developing structured strategies for the application of skills in everyday life. Her goal is to help clients cultivate sustainable coping mechanisms, resilience, and measurable growth in overall functioning.\n\nOutside of her professional work, Octavia runs a home baking business and enjoys reading, traveling, and spending quality time with family and friends." },
  { slug: "amina-huric-lmsw", name: "Amina Huric, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "amina-huric-lmsw", prescribes: false,
    education: "Licensed Master Social Worker",
    focus: ["Children, adolescents, adults & families", "LGBTQ+ communities", "Anxiety, depression, ADHD, bipolar & OCD", "Trauma & substance use", "Grief, stress & self-esteem"],
    quote: "“Even the smallest act of kindness can change someone's world.” – Anne Frank",
    bio: "Amina is a Licensed Master Social Worker (LMSW). She works with children, adolescents and adults, specializing in helping individuals navigate life's challenges and find balance. Her clinical work centers on individuals struggling with anxiety, depression, relationship issues, grief, trauma, and substance use and she is dedicated to empowering individuals to find practical tools that foster long-term well-being. Amina strives to create a safe, supportive, and engaging environment where individuals feel heard and understood.\n\nAmina believes that meaningful change happens through trust, consistency, and connection and takes a warm, patient, and collaborative approach, meeting individuals where they are and supporting them at their own pace. She combines evidence-based modalities such as Cognitive Behavioral Therapy, Dialectical Behavior Therapy and Motivational Interviewing, which focuses on creating a compassionate, non-judgmental space for self-exploration and growth.\n\nOutside of her clinical work, Amina is passionate about hiking, traveling, and exploring coffee shops." },
  { slug: "angela-pierce-lmsw", name: "Angela Pierce, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "angela-pierce-lmsw", prescribes: false,
    education: "Bachelor's in Social Work, Central Connecticut State University; Master's in Social Work, Southern Connecticut State University",
    focus: ["Kids, teens & adults (esp. young adults)", "CBT & mindfulness-based practices", "Somatic techniques", "Anxiety, depression & ADHD", "Addiction, self-esteem & life transitions", "Inclusive, identity-affirming care"],
    quote: null,
    bio: "Angela is a Licensed Master Social Worker (LMSW). She is a compassionate and intuitive therapist dedicated to guiding her clients toward healing the mind, body, and soul. She received her bachelor's degree in social work from Central Connecticut State University and her master's degree in social work from Southern Connecticut State University. As a Licensed Master Social Worker, Angela integrates multiple therapeutic modalities such as Cognitive Behavioral Therapy (CBT), mindfulness-based practices, and somatic techniques to create individualized treatment plans that honor each person's unique journey. Angela emphasizes the importance of client-centered therapy and tailoring interventions and treatment to the specific needs of the individual.\n\nAngela loves working with kids, teens, and adults. She brings warmth, compassion and new ideas for healing to every session with her clients. She is especially passionate about working with young adults and is someone who genuinely enjoys supporting people in the exciting but often challenging stage between adolescence and full adulthood. She understands that this period comes with big transitions that include figuring out identity, navigating relationships, managing academic or career pressures, living more independently, and dealing with emotional ups and downs.\n\nAngela offers support for individuals dealing with anxiety, depression, addiction, ADHD, behavioral issues, life transitions, self-esteem, and confidence building. Angela is welcoming and provides an inclusive space that honors and respects all identities including gender, sexuality, race, and cultural background.\n\nBeyond her practice, Angela finds joy in spending time with loved ones. She is a devoted food enthusiast and appreciates warmly designed spaces. Angela loves to travel, especially to tropical islands where the rhythm of the waves soothes her soul. The beach is her sanctuary, a place where she feels grounded and free. Angela enjoys all things sparkly and bright, bringing her endless delight, reflecting her vibrant, heart-centered approach to both her work and her life." },
  { slug: "kate-henneberry-lmfta", name: "Kate Henneberry, LMFTA", credentials: "LMFTA", role: "Licensed Marriage & Family Therapist Associate", category: "clinical", photo: null, prescribes: false,
    education: "Bachelor's in Human Development & Family Sciences, University of Connecticut; Master's in Marriage & Family Therapy, Southern Connecticut State University",
    focus: ["Systems-based therapy", "CBT", "Structural Family Therapy", "Narrative Therapy", "Solution-Focused Therapy", "Play & creative projects"],
    quote: "“Promise me you'll always remember: You're braver than you believe, and stronger than you seem, and smarter than you think.” — Christopher Robin, Winnie the Pooh",
    bio: "Kate Henneberry is a Licensed Marriage and Family Therapist Associate. She received her Bachelor's degree in Human Development and Family Sciences from the University of Connecticut as well as a Master's degree in Marriage and Family Therapy from Southern Connecticut State University. Kate's educational background has had strong foundations in systems theory, suggesting that individual experiences are a product of our relationships, communities, and broader societal contexts. Kate provides therapy that utilizes this systemic lens to promote growth through exploration of the self and ways of relating to one and other.\n\nKate believes that change is always occurring in some form, whether we are attuned to that process or not. She strives to create a space that fosters connectedness, curiosity, courage, and compassion to best support clients as they navigate challenging periods of change and growth. Kate adapts various evidence-based approaches to best fit the needs of each client, often utilizing elements of CBT, Structural Family Therapy, Narrative Therapy, and Solution Focused Therapy. Kate also often includes play and creative projects to practice mindfulness and deepen self-understanding.\n\nOutside of therapy, Kate enjoys traveling, music, trying new crafts, and spending time with friends and family, including her three-legged rabbit." },
  { slug: "eleni-fatsis-lmsw", name: "Eleni Fatsis, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "eleni-fatsis-lmsw", prescribes: false,
    education: "Degree in Education & Child Study, Smith College; MSW, University of Southern California",
    focus: ["Adult women", "Trauma & complex PTSD", "Survivors of violence/assault", "Peri- & post-menopausal women", "First responders, law enforcement & veterans", "Motivational Interviewing & CBT"],
    quote: "“We live better in seeking to become better.” · “The mind is everything; what you think — you can become.” — Socrates",
    bio: "Eleni graduated from Smith College with a degree in Education and Child Study. With more than 15 years experience working in educational, non-profit, state and federally funded positions, she transitioned to supporting small business owners and entrepreneurs. More recently, Eleni completed the MSW program at the University of Southern California. Her clinical community practicum focused on supporting the journey of college students and studying the impact of interpersonal violence. In her clinical work, Eleni espouses a holistic approach centered on healing in all aspects of a human being.\n\nShe utilizes evidence-based modalities like Motivational Interviewing (MI), Cognitive Behavioral Therapy (CBT) specifically with a Problem Solving Emphasis, Relational Cultural Theory and Neurosequential Model of Therapeutics (NMT) while also utilizing somatic interventions that can resonate with individuals in the aftermath of experiencing trauma.\n\nEleni's clinical approach to the therapeutic journey begins by developing a plan based on a holistic assessment of ones biopsychosocial and spiritual factors (BPSS Assessments) that impacts a person's life. By understanding the physical, psychological, social and spiritual areas of ones life, the therapeutic dynamic can enhance the healing process in all areas of ones personal and professional life.\n\nEleni rejects the antiquated notion that a clinician has absolute expertise; rather, the therapeutic environment is a shared collaborative space where the therapist and the individual seeking support explore modalities and interventions that resonate with that individual's goals. Her therapeutic approach is trauma informed, strength-based and built on a foundation of cultural humility.\n\nOutside of work, Eleni is a conservationist who enjoys outdoor recreational activities. She is a classically trained Byzantine Chanter. Her passion is documenting women's experiences. She provides Spiritual Wellness Coaching and Workshops for women who share her Greek Orthodox heritage. She continues providing coaching and consulting to entrepreneurs, small business owners and others seeking coaching for wellness and optimal functioning." },
  { slug: "nathan-truong-lmft-a", name: "Nathan Truong, LMFT-A", credentials: "LMFT-A", role: "Licensed Marriage & Family Therapist Associate", category: "clinical", photo: "nathan-truong-lmft-a", prescribes: false,
    education: "Master's in Marriage & Family Therapy; Bachelor's in Psychology & Communication (minor in Women's, Gender & Sexuality Studies)",
    focus: ["Couples & family therapy", "Neurodivergent individuals (ADHD, Autism)", "Diverse cultural identities", "Group & IOP sessions", "Communication & conflict resolution", "Anxiety, depression & grief"],
    quote: null,
    bio: "Nathan is a Marriage and Family Therapist Associate. He holds a master's degree in Marriage and Family therapy as well as a bachelor's in psychology and communication with a minor in Women's gender and sexuality studies.\n\nNathan has extensive experience in both outpatient and in-home settings working with adolescents, adults, persons of diverse cultural identities, and Neurodivergent individuals such as persons with Autism Spectrum Disorders and ADHD experiencing anxiety, depression, relationship issues, life transitions, self-esteem concerns, and behavioral challenges.\n\nNathan is dedicated to helping individuals, couples, and families navigate life's challenges and strengthen their relationships. With compassion and kindness, Nathan applies evidence-based treatments; he specializes in communication issues, conflict resolution, and emotional connection. Nathan believes in creating a safe, supportive space where clients can explore patterns, heal from past wounds, and build healthier dynamics. He offers therapy in person and via telehealth." },
  { slug: "madison-anderson-lmsw", name: "Madison Anderson, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "madison-anderson-lmsw", prescribes: false,
    education: "B.S.W., Eastern Connecticut State University; M.S.W., Quinnipiac University",
    focus: ["Children, adolescents & young adults", "Anxiety, depression & ADHD", "Personality disorders & psychosis", "Relationship issues & life transitions", "LGBTQ+ identity & transitions"],
    quote: "“We delight in the beauty of the butterfly, but rarely admit the changes it has gone through to achieve that beauty.” — Maya Angelou",
    bio: "Madison earned her Bachelor's degree in Social Work from Eastern Connecticut State University and continued her education by completing her Master's degree in Social Work at Quinnipiac University. Madison emphasizes the importance of collaboration, meeting clients where they are, and supporting them in building on their existing strengths to create positive change.\n\nMadison has worked with children, teens, adults, and families, both individually and within group therapy services. She is passionate about supporting individuals who experience challenges at school, friendship troubles, and difficult family dynamics. Madison is highly experienced in working with individuals who struggle with anxiety, depression, ADHD, personality disorders, psychosis, relationship issues, and life transitions. Her goal is to provide a safe and welcoming space where clients can explore their experiences, heal from challenges, and feel confident within their mental health journey.\n\nMadison combines evidence-based practices such as Cognitive Behavioral Therapy (CBT), Dialectical Behavioral Therapy (DBT), Motivational Interviewing (MI), and mindfulness practices with a strength-based approach to meet individuals where they are.\n\nOutside of work, Madison enjoys fitness, spending time with animals, and spending time with her loved ones." },
  { slug: "kris-feller-lmsw", name: "Kris Feller, LMSW, RSS", credentials: "LMSW, RSS", role: "Licensed Master Social Worker", category: "clinical", photo: "kris-feller-lmsw", prescribes: false,
    education: "B.S.W., Southern Connecticut State University; M.S.W., University of Denver",
    focus: ["Children, adolescents & adults", "Depression, anxiety & mood disorders", "Addiction & recovery support", "Trauma & stress-related disorders", "LGBTQIA+ & domestic violence", "Holistic & Eastern modalities"],
    quote: "“The Definition of Success is Hope.”",
    bio: "Kris (Kristen) Feller, LMSW, RSS, is a Licensed Masters Social worker. She earned her bachelors' in Social Work from Southern Connecticut State University and her masters' in Social Work from the University of Denver. Kris works with children, adolescents, and adults. Kris has a strong clinical background in mental health care, specializing in high-acuity settings where she supports individuals in crisis and develops personalized aftercare plans to promote long-term recovery.\n\nShe takes a culturally sensitive, warm, and collaborative approach, striving to create a safe and supportive space that promotes personal growth and overall well-being. Her passion lies in working with individuals facing challenges such as depression, anxiety, addiction, trauma and stress-related disorders, relational difficulties, life transitions, and behavioral disorders.\n\nKris's therapeutic approach is client-centered, emphasizing collaboration to support holistic growth—mind, body, and soul. She integrates evidence-based modalities, including Acceptance and Commitment Therapy (ACT), Cognitive Behavioral Therapy (CBT), Dialectical Behavioral Therapy (DBT), Solution-Focused Brief Therapy (SFBT), and Motivational Interviewing (MI). Believing that therapy is not a one-size-fits-all process, Kris tailors her approach to meet each client's unique needs.\n\nKris works diligently towards lifting the veil of mental health and expanding Hope through mutual “humanness”. She is a fierce advocate that every part of individuality deserves recognition and respect in pursuit of healing. Kris believes that each interaction presents an opportunity to learn and grow. In her free time, she is likely engulfed in nature therapy, mindful practice, furry friends, or all things Colorado. A treatment motto might be “let's get creative!”" },
  { slug: "mariah-thomas-lmsw", name: "Mariah Thomas, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "mariah-thomas-lmsw", prescribes: false,
    education: "M.S.W., Springfield College",
    focus: ["Children, adolescents & adults", "Anxiety, depression & ADHD", "Behavioral disorders & OCD", "Autism & adjustment disorders", "Grief & loss", "Substance misuse"],
    quote: "“If you're always trying to be NORMAL, you will never know how AMAZING you can be.” — Maya Angelou",
    bio: "With a Master's in Social Work from Springfield College, Mariah has been working for 10 years as a social worker in the field of mental health. Mariah has experience providing counseling services to children, adolescents and adults of all ages as well as families. Mariah is dedicated to educating, empowering and supporting children, adolescents, and adults at all different stages of life. One of Mariah's primary goals is to foster real, sustainable change that will produce a lasting and positive impact in the lives of her clients.\n\nMariah has training in Motivational Interviewing, Solution-focused, Person Centered, Cognitive Behavioral Therapy, Trauma-Focused, Mindfulness and Art Therapy. In addition, Mariah utilizes holistic methods along with a strength-based approach to focus on empowering clients by highlighting their inherent strengths and capabilities. Mariah's therapeutic approach is one of collaboration, connection, trust, & respect. As a team, she helps her clients address and overcome the barriers blocking them from living the life they deserve.\n\nAs a Licensed Master Social Worker, Mariah has clinical experience providing treatment for Anxiety, Depression, ADHD, Behavioral Disorders, Stress, OCD, Autism, Adjustment Disorders, Communication issues, Family issues, Grief and Loss, and Substance Misuse. Overall, Mariah believes that an individual's resilience accompanied by a safe therapeutic environment provides a fundamental healing foundation to overcome all challenges." },
  { slug: "patricia-nogelo-ph-d-lcsw", name: "Patricia Nogelo, PhD, LCSW", credentials: "PhD, LCSW", role: "Licensed Clinical Social Worker", category: "clinical", photo: "patricia-nogelo-phd-lcsw", prescribes: false,
    education: "PhD in Clinical Psychology, Universidad Central de Venezuela (Caracas), 2002",
    focus: ["Trauma (children, adolescents & families)", "Parent-child attachment", "Conflict resolution & parenting", "Acculturation & adjustment", "Grief & coping with complex medical diagnoses", "Bilingual / bicultural (Latino & refugee families)"],
    quote: null,
    bio: "Patricia obtained her PhD in clinical psychology at the Universidad Central de Venezuela in Caracas in 2002. Soon after she completed her training she was hired to provide clinical assessments, diagnostic evaluations, crisis interventions, and therapy to immigrant children and families at Clifford Beers Community Care Center. In 2011 Patricia was promoted to Program Manager for all Trauma Services. In 2013, after she obtained her LCSW she became faculty at Southern Connecticut State University where she has been teaching a clinical practicum class to MSW candidates. In 2016 she joined the Yale Pediatric Primary Care Center and in addition to providing clinical services to children and families, she provided clinical training to medical students and residents.\n\nPatricia facilitated psychoeducation groups for Latino and Refugee families. She also provided advocacy in collaboration with the Medical Legal Partnership. Patricia is a bilingual-bicultural trained in psychodynamics and she is certified in Trauma Focused Cognitive Behavioral Therapy. Areas of expertise include work with children, adolescents and families affected by trauma, parent-child attachment, conflict resolution, parenting, acculturation and adjustment issues, grief and coping with living with complex medical diagnosis.\n\nPatricia is certified in Seminar Field Instruction (SIFI) and she has over 12 years of experience supervising MSW students and post master social work professionals." },
  { slug: "william-telemaque-lpca", name: "William Telemaque, LPCA", credentials: "LPCA", role: "Licensed Professional Counselor – Associate", category: "clinical", photo: "william-telemaque-lpca", prescribes: false,
    education: "B.A. in Psychology (Summa Cum Laude, clinical counseling concentration); M.A. in Clinical Counseling, Albertus Magnus College; doctoral candidate in Forensic Psychology, Walden University",
    focus: ["Children, teens & adults", "Anxiety, depression & trauma", "ADHD & SUD/addiction", "LGBTQ+ affirming care", "Mood, behavioral & personality issues", "Couples & family therapy"],
    quote: null,
    bio: "William is a Licensed Professional Counselor -Associate, he brings several years of knowledge and experience to the HHS team. He has worked for almost a decade providing mental health services for adolescents and adults. He holds a Bachelor's degree, Summa Cum Laude, in psychology, with concentration in clinical counseling. He also has a Master's degree in Clinical Counseling from Albertus Magnus College. Presently, he is a doctoral candidate for Forensic Psychology at Walden University.\n\nWilliam provides group, couples, family, and individual therapy to children, teens, and adults at HHS. William's focus is helping and transforming clients who have anxiety, depression, trauma, ADHD, SUD, and addiction based disorders. He is passionate about helping and working with clients within the LGBTQ+ community. Apart from his clinical experience, William had done research work on ADHD, psycho-somatic disorders and eating disorders. He has led several research teams at the American Psychological Association (APA) and the Association for Psychological Science (APS), while at Fielding University.\n\nWilliam is adept at helping clients dealing with several kinds of mental health challenges, including mood, behavioral, and personality issues, as well as substance abuse. William uses the following treatment modalities in this therapy: Cognitive Behavioral Therapy, Acceptance Commitment Therapy, Dialectical Behavioral Therapy, along with other Person-Centered approaches. He posits that one of the keys to successful therapy is building and maintaining the therapeutic relationship and alliance. To that end, he will ensure that his clients feel safe at all times, while in therapy. His clinical approach is rooted in the healing power of self-discovery and self acceptance. He postulates that hope is important and that he must always have hope for the client even at times when they feel like giving up.\n\nWilliam spends a lot of his spare time in community service, and has done extensive travel to several parts of the world to inspire positivity and optimism to those in need. His hobbies include chess, swimming, and basketball. He currently swims with the USA Masters swim team in Shelton CT." },
  { slug: "kimberly-devine-lcsw", name: "Kimberly Devine, LCSW", credentials: "LCSW", role: "Licensed Clinical Social Worker", category: "clinical", photo: "kimberly-devine-lcsw", prescribes: false,
    education: "B.S. in Psychology & Criminal Justice, Endicott College; M.S.W. (Case Work concentration), UConn School of Social Work",
    focus: ["Kids, teens & adults", "Relationship issues & PTSD", "Depression & anxiety", "Domestic violence & trauma", "Parenting, co-parenting & blended families", "Substance use, ACOA & personality disorders"],
    quote: null,
    bio: "Kimberly Devine, LCSW, is a Licensed Clinical Social Worker who received a Bachelor of Science Degree in Psychology and Criminal Justice from Endicott College, and Master's degree with concentration in Case Work from UConn School of Social Work. Kim began her career as a Counselor and Case Manager in a long-term residential treatment program for substance abuse women and their children, transitioning into a leadership position as a Youth Service Professional and Elderly Caretaker.\n\nKim is passionate about assuring every client maintains dignity, self-worth, and self-respect in a non-judgmental, transparent environment, while establishing balance for a better quality, more manageable lifestyle. Kim works with kids, teens, and adults to initiate cognitive and behavioral changes through individual, couples, and family therapy, inclusive of all communities. Her unwavering compassion enhances the ability to maintain a person-centered collaborative treatment approach, and a deep understanding of various evidence-based and strengths-based treatment modalities.\n\nKim has diverse experience that includes, but not limited to, relationship issues, PTSD, depression, anxiety, domestic violence, parenting, co-parenting, blended families, family issues, Attachment, substance use/abuse, ACOA, Personality Disorders and trauma. She believes in the power of working gently throughout the therapeutic process to encompass safety, security and empowerment while breaking down life's complexities.\n\nKim enjoys spending quality time with her family, German Shepherd, and friends. She is always open to partaking in active activities, running, shopping, traveling (prefers tropical locations), watching sports, reading, gardening, and learning new things (personally and professionally)." },
  { slug: "michelle-munasami-lmft", name: "Michelle Munasami, LMFT", credentials: "LMFT", role: "Licensed Marriage & Family Therapist", category: "clinical", photo: "michelle-munasami-lmft", prescribes: false,
    education: "Bachelor's and Master's degrees, University of Saint Joseph",
    focus: ["Children, adolescents, adults & families", "Parenting & relationship problems", "Anxiety & depression", "Bipolar disorder & ADHD", "Behavioral disorders", "Divorce & blended families"],
    quote: null,
    bio: "Michelle Munasami, LMFT is a licensed marriage and family therapist in the state of Connecticut. She received both her Bachelor's and Master's from the University of Saint Joseph. Michelle has over 15 years of expertise working with both adults and children, individually and as families. Michelle utilizes many different therapeutic practices which include Cognitive Behavioral Therapy (CBT), Solution-Focused Therapy, Mindfulness, and Dialectical Behavioral Therapy (DBT). Michelle is solution-focused and collaborative and moves clients towards their desired goals.\n\nMichelle stays busy with her three children and husband and enjoys kickboxing and traveling in her free time." },
  { slug: "christina-coelho-lmsw", name: "Christina Coelho, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "christina-coelho-lmsw", prescribes: false,
    education: "Master's degree, University of Connecticut (concentration in individual, group & family therapy)",
    focus: ["Children, adolescents, adults, couples & families", "Depression, anxiety & mood disorders", "ADHD & behavior disorders", "Trauma-related disorders", "CBT, DBT, TF-CBT & Narrative Therapy", "Bilingual / multilingual care"],
    quote: null,
    bio: "Christina Coelho is a Bilingual Licensed Master Social Worker in the state of CT specializing in client centered work utilizing solution/focused and family systems modalities with children, adolescents, and adults. She received her master's degree from UConn with a concentration in individual, group, and family therapy. Christina has worked in the human services field and varying psychiatric settings since 2011, including a residential treatment facility for traumatized, Autistic, genetic, and intellectually disabled children and in-home settings working with acute psychiatric children, adolescents, and families. In addition, she has worked in a therapeutic alternative school as a social worker with ages k-12th grade. Additional roles consist of working as a therapeutic mentor, a child development specialist at an extended day treatment program, a crisis responder, and a therapist/advocate for victims of domestic violence, and worked with dually diagnosed young adults.\n\nChristina is passionate about helping clients identify their core values and motivation for change so they may live a life in line with their authentic integrity. From your first meeting with Christina, she creates a welcoming, safe, and culturally competent environment. To foster her clients healing journey, Christina adopts a blend of trauma-focused and evidence-based interventions and has experience diagnosing and treating: Depression, Anxiety, Mood Disorders, ADHD, behavior disorders, and trauma related disorders. Christina works with a combination of therapeutic interventions such as: CBT, DBT, TF-CBT, Narrative Therapy, and Motivational Interviewing. Christina practices with children, adolescents, adults, couples, and families. A first generation American born to an immigrant family, she speaks Greek, Portuguese, Spanish, and conversational American Sign Language, and has experience working with LGBTQA+ populations.\n\nIn her free time, Christina enjoys spending time with family and friends, baking/cooking, traveling, and spending time with her dogs and significant other." },
  { slug: "chelsey-micciche-lpc", name: "Chelsey Micciche, LPC", credentials: "LPC", role: "Licensed Professional Counselor · Individual & Family Counseling", category: "clinical", photo: "chesley-micciche-lpc", prescribes: false,
    education: "Licensed Professional Counselor (certified in Cognitive Processing Therapy; trained in TF-CBT)",
    focus: ["Children, adolescents, adults & families", "Anxiety, depression & mood disorders", "ADHD, Autism & behavioral issues", "Attachment & trauma-related disorders", "Sexuality & gender", "Stress, OCD, panic & phobias"],
    quote: null,
    bio: "Chelsey Micciche, LPC is a Licensed Professional Counselor experienced in working with adolescents, families and adults in addressing a variety of mental health needs. She has provided intensive in-home services to high-risk children and their families with delivering crisis management, parent guidance and school-based support. She has experience working with individuals in an outpatient setting, providing therapeutic support and treatment to address a variety of mental health needs such as depression and other mood-related disorders, anxiety, ADHD, attachment and/or behavioral issues and trauma-related disorders.\n\nChelsey uses an eclectic approach as she incorporates evidence-based framework from trauma-informed, strength-based and cognitive practices. She embraces the fundamental teachings of humanistic psychology and Rogerian therapy, emphasizing the importance of the therapeutic relationship and encouraging personal growth, self-awareness and healing throughout the therapeutic process. By using a person-centered approach, Chelsey brings compassion, warmth and understanding into her client's unique journey in overcoming challenges and achieving their goals. She is certified in Cognitive Processing Therapy and has training in Trauma-Focused Cognitive Behavioral Therapy (TF-CBT).\n\nChelsey enjoys spending quality time with her family, visiting new places and going on scenic nature walks. She likes to participate in seasonal activities such as kayaking and snowboarding. Many people describe Chelsey as being easy-going, kind-hearted and spontaneous, always ready to experience new things and create memorable moments with the people she loves." },
  { slug: "melissa-holznagel-lcsw", name: "Melissa Holznagel, LCSW, MEd", credentials: "LCSW, MEd", role: "Licensed Clinical Social Worker", category: "clinical", photo: null, prescribes: false,
    education: "Bachelor's in General Education & Master's in Special Education, Ottawa University; Master's in Social Work, Saint Mary's University of Minnesota",
    focus: ["Children, adolescents, young adults & adults", "ADHD, ASD & intellectual development disorders", "Bipolar & anxiety/depressive disorders", "Trauma & self-harm/suicidality", "Anger, life skills & communication", "LGBTQIA+ affirmative care"],
    quote: null,
    bio: "Melissa Holznagel, LCSW, MEd, is a Licensed Clinical Social Worker in the state of Connecticut. She attended Ottawa University for her bachelor's degree in general education and her master's degree in special education. Melissa obtained her master's degree in social work from Saint Mary's University of Minnesota.\n\nMelissa has experience in various capacities working with children, adolescents, young adults, and adults. She has a deep level of understanding children's emotional development and behavior. She started her career working in education as a Special Education Teacher, General Education teacher, pre-school teacher, and an In Home service provider for children with special needs. Melissa' clinical experience has included working within the community supporting adolescents, young adults, and adults. She enjoys working with children, adolescents, and adults using a variety of treatment techniques and strategies. Melissa loves watching her clients transform over time to becoming their best selves and living their lives to the fullest extent.\n\nMelissa is passionate about affirming, compassionate and supportive care where she will meet you where you are to support your mental health journey and needs. Melissa is non-judgmental, empathetic, and engaging to all who walk through her doors. She is dedicated to utilizing a strengths-based, client centered approach to support you in identifying and working towards your specific goals. Melissa has completed many LGBTQIA+ affirmative trainings, including Affirmative Care for Transgender and Gender Non-Conforming People, and Creating a Trans-affirming and Inclusive Environment. Melissa utilizes the treatment approaches of dialectical behavioral therapy (DBT), cognitive-behavioral therapy (CBT), motivational interviewing (MI), play or art therapy, and mindfulness techniques.\n\nIn her spare time Melissa enjoys watching her favorite TV shows, traveling, and spending time with her family and friends." },
  { slug: "jessenia-medina-lpc-ncc", name: "Jessenia Medina, LPC, NCC", credentials: "LPC, NCC", role: "Licensed Professional Counselor", category: "clinical", photo: "jessenia-medina-lpc-ncc", prescribes: false,
    education: "Master's in Counselor Education (Clinical Professional Counseling), Central Connecticut State University",
    focus: ["Children, adolescents, adults & families", "Depression, anxiety & PTSD", "Mood disorders, trauma & OCD", "ADHD & panic attacks", "Substance abuse & anger management", "Bilingual (English / Spanish)"],
    quote: null,
    bio: "Jessenia Medina is a Bilingual Licensed Professional Counselor (LPC) and a National Certified Counselor (NCC) with the state of Connecticut offering services in both English and Spanish. She received her Master's in Counselor Education with a specialization in Clinical Professional Counseling from Central Connecticut State University. She is versed in working with individuals struggling with mental health and substance abuse disorders. She has worked in a variety of settings including schools, inpatient, outpatient and in-home providing therapy services.\n\nWhen working with clients, Jessenia makes sure she builds rapport and establishes a safe and comfortable environment for individuals to engage in therapy. She helps individuals make that first step and guides them into the process of therapy.\n\nJessenia is open-minded, creative and supportive. She utilizes a person-centered approach and incorporates psycho-social interventions with Cognitive Behavioral Therapy (CBT) to help improve mental health through personal coping strategies that target problem solving. She also incorporates Solution-Focused Therapy through a collaborative approach to help identify client needs and goals.\n\nOutside of work Jessenia enjoys spending time with her 2 poodles on long walks, traveling to new destinations, and using her creative outlet in arts and crafts." },
  { slug: "stacy-piscottano-lmsw", name: "Stacy Piscottano, LMSW", credentials: "LMSW", role: "Licensed Master Social Worker", category: "clinical", photo: "stacy-piscottano-lmsw", prescribes: false,
    education: "Social Work degree, Sacred Heart University",
    focus: ["Children, adolescents & families", "Anxiety, depression & ADHD", "Behavioral difficulties & emotional regulation", "Trauma", "Family conflict", "Crisis support"],
    quote: "“The only way to do great work is to love what you do.” — Steve Jobs",
    bio: "Stacy is a Licensed Master Social Worker who received her Social Work degree from Sacred Heart University. She has committed her work to helping children, adolescents and families navigate life's challenges. Over the last ten years, Stacy has worked in multiple settings including outpatient, inpatient and school settings. She has extensive experience working with children and adolescents at The Institute of Living in Hartford and working with kids in crisis.\n\nShe enjoys working with children, teens, and their families and is well versed in working with defiant or more behavioral kids. Her therapeutic approach works very well due to her ability to connect with kids that can be reactive and that struggle with emotional regulation. She develops behavioral plans and goals that are progressive so that over time, the difficult behaviors diminish and the child's strengths shine through.\n\nStacy strives to be authentic and transparent with clients to establish trust. Therapy can be difficult especially for children and adolescents, for some, their ability to trust has been broken. Stacy is a strong therapist and has six children of her own, so she is a dedicated therapist who can flex with any situation. Her approach combines strength-based perspective, evidence-based theories and a person-centered approach, tailoring treatment to meet the unique needs of each client.\n\nStacy meets clients where they are, with a nurturing, straightforward and collaborative approach to help them reach their full potential with a focus on empowerment and developing effective coping strategies. She promotes and encourages “progress not perfection.” She specializes in working with children and adolescents experiencing a range of issues, including anxiety, ADHD, depression, trauma, behavioral difficulties, and family conflict. She is committed to helping young clients build resilience and confidence to achieve their goals. Her greatest joy is seeing progress in clients and she is honored to be part of their journey.\n\nDuring her free time, she enjoys spending time with her family and friends, baking/cooking, and going to the beach. The sound of the ocean and the sand between her toes is her happy place!" },
  { slug: "sheryll-waring-lpc-ldac", name: "Sheryll Waring, LPC, LDAC", credentials: "LPC, LDAC", role: "Licensed Professional Counselor", category: "clinical", photo: "sheryll-waring-lpc-ladc", prescribes: false,
    education: "Master's in Counseling, Saint Joseph University; Advanced Trauma Training (Ricky Greenwald); Behavioral Analysis training, University of Massachusetts",
    focus: ["Adults, adolescents & children", "Applied Behavioral Analysis (ABA) consults", "Trauma & memory reconciliation", "Depression, anxiety, mood & ADHD", "Life transitions & loss", "Parenting children with special needs"],
    quote: null,
    bio: "Sheryll Waring is a Licensed Professional Counselor in the State of Connecticut. She has a passion for helping people learn how to heal themselves. She uses metaphors, humor, and behavior changes with her patients often. Her work consists of hands-on techniques that decrease or eliminate symptoms. Some areas of interest include decreasing upsetting memories and focusing on current life goals, understanding past patterns in relationships, and loving ourselves.\n\nShe has worked in a variety of behavioral health settings including outpatient and residential with a focus on both Cognitive Behavioral theories, Dialectical and Behavioral Therapies. Sheryll is trained in Behavior Support Plans, Functional Behavioral Analysis, Trauma Informed Therapy, Applied Behavioral Analysis, FLASH Therapy and Cognitive Affective Therapy." },
  { slug: "erica-schwartz-lcat", name: "Erica Schwartz, LCAT", credentials: "LCAT · Board Certified Art Therapist", role: "Licensed Creative Arts Therapist", category: "clinical", photo: "erica-schwartz-lcat", prescribes: false,
    education: "Board Certified & Licensed Clinical Art Therapist (34+ years across outpatient, residential, inpatient & partial-hospitalization settings)",
    focus: ["Individual & family art therapy", "Expressive arts therapy", "Emotional expression & self-awareness", "Relationships & communication", "Groups — children, teens & parents"],
    quote: null,
    bio: "Erica Schwartz is a Board Certified and Licensed Clinical Art Therapist. Her career as an art therapist has spanned well over 34 years. She has provided clinical art therapy services to children, adolescents, families and adults in a variety of clinical settings including outpatient, residential, inpatient, and partial hospitalization. She has conducted numerous art therapy experientials and presentations.\n\nShe believes the purpose of art therapy is to produce introspection and an awareness of emotions, thoughts, and feelings and is a therapeutic process to assist people in progressing towards treatment goals by utilizing a variety of artistic medias. Expressive arts therapy combines psychology and the creative process to promote emotional growth and healing. Expressive Arts Therapy is a multi-arts or intermodal approach to psychotherapy and counseling. It is believed that we all have an inborn desire to create – be it Music, theater, poetry or other artistic forms – as a therapeutic tool to help initiate change. The purpose is to nurture deep personal growth and transformation.\n\nArt Therapy encourages individuals to use multiple senses to explore their inner and outer worlds through the experience and creation of different art forms. Here's who would benefit and enjoy art therapy: Adults, Adolescents and Children who struggle with emotional expression, relationships, communication, and self-awareness. You don't need to be an artist, but you are looking for a creative way to explore relationships and patterns of behaviors that you wish to change. Come join me as we explore and play with art therapy activities that will encourage wellness and good self-care.\n\nAt Hopewell Health Solutions, Erica's practice includes children, adolescents, and adults. Erica's other professional interests include group work and training." },
  { slug: "karla-dunkley-lpca", name: "Karla Dunkley, LPCA", credentials: "LPCA", role: "Licensed Professional Counselor Associate", category: "clinical", photo: null, prescribes: false,
    education: "Master's in Counselor Education (Clinical Professional Counseling), Central Connecticut State University",
    focus: ["Children, adolescents & adults", "ADD/ADHD, anxiety & depression", "Substance use / addiction", "Trauma, mood disorders & OCD", "Anger management & crisis intervention", "Group counseling (trauma, DV, parenting, women's issues)"],
    quote: null,
    bio: "Karla is a Licensed Professional Counselor Associate in the state of Connecticut, holding a master's degree in Counselor Education with a specialization in Clinical Professional Counseling from Central Connecticut State University. Karla provides support to her clients in exploring and determining pathways towards a purposeful and well-balanced life, while acknowledging and addressing any past issues without allowing them to dominate the present.\n\nKarla's diverse experiences have equipped her with the tools to support others effectively. Karla has a background in counseling in multiple settings working with children, teens, and adults. She enjoys doing both process groups and individual counseling. Karla enjoys working with clients that have complex situations and brings empathy, non-judgment, and understanding into all of her sessions. She creates tailored, specialized treatment plans with specific goals and objectives for guiding her patients into self-sustaining healthy behavior patterns for life.\n\nKarla employs Dialectical Behavioral therapy (DBT), Cognitive Behavioral Therapy (CBT) and Client-Centered Therapy to help clients identify and address their presenting issues. By focusing on “the how” and connecting behaviors to their negative impacts, Karla assists clients in understanding and overcoming obstacles. Karla's approach is characterized by compassion, transparency, respect, and honesty, fostering meaningful connections with clients.\n\nIn her free time, Karla enjoys being physically active to promote a healthy life balance, traveling, connecting with family and friends, and practicing mindfulness activities." },
];
